test("IAbstractItem deserialization fail", () => {
  const jsonable = "This is not a IAbstractItem.";

  const instanceOrError = AasJsonization.abstractItemFromJsonable(
    jsonable
  );
  expect(instanceOrError.error.message).toStrictEqual(
    "Expected a JSON object, but got: string"
  );
});

